class Solution:
    def minInsertions(self, s: str) -> int:
        stack = []
        insertions = 0
        for char in s:
            if char == '(':
                stack.append(char)
            elif char == ')':
                if stack and stack[-1] == '(':
                    stack.pop()
                else:
                    insertions += 1
        insertions += 2 * len(stack)
        return insertions
